create table if not exists access_operator_roles (access_operator_id bigint not null, role_code varchar(32) not null check (role_code in ('TENANT_ADMIN','REVIEW_OWNER','FINAL_APPROVER','ESCALATION_OWNER','INTEGRATION_ADMIN','INTEGRATION_OPERATOR')), primary key (access_operator_id, role_code));
create table if not exists access_operator_warehouse_scopes (access_operator_id bigint not null, warehouse_code varchar(40) not null, primary key (access_operator_id, warehouse_code));
create table if not exists access_operators (active boolean not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint, updated_at timestamp(6) with time zone not null, actor_name varchar(80) not null, display_name varchar(80) not null, description varchar(160), primary key (id), unique (tenant_id, actor_name));
create table if not exists access_users (active boolean not null, password_change_required boolean not null, access_operator_id bigint not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, password_updated_at timestamp(6) with time zone not null, session_version bigint not null, tenant_id bigint, updated_at timestamp(6) with time zone not null, username varchar(80) not null, full_name varchar(120) not null, password_hash varchar(120) not null, primary key (id), unique (tenant_id, username));
create table if not exists alerts (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint, updated_at timestamp(6) with time zone not null, severity varchar(32) not null check (severity in ('MEDIUM','HIGH','CRITICAL')), status varchar(32) not null check (status in ('ACTIVE','RESOLVED')), type varchar(32) not null check (type in ('LOW_STOCK','DEPLETION_RISK','FULFILLMENT_BACKLOG','DELIVERY_DELAY_RISK','FULFILLMENT_ANOMALY')), title varchar(180) not null, description varchar(1024) not null, impact_summary varchar(1024) not null, policy_explanation varchar(1024), recommended_action varchar(1024) not null, primary key (id));
create table if not exists audit_logs (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, status varchar(32) not null check (status in ('SUCCESS','FAILURE')), request_id varchar(64) not null, tenant_code varchar(64), action varchar(96) not null, actor varchar(96) not null, target_type varchar(96) not null, source varchar(128) not null, target_ref varchar(256) not null, details varchar(2048) not null, primary key (id));
create table if not exists business_events (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, event_type varchar(48) not null check (event_type in ('ORDER_INGESTED','ORDER_STATUS_TRANSITIONED','PRODUCT_CATALOG_UPDATED','INVENTORY_UPDATED','INVENTORY_RECEIVED','INVENTORY_ADJUSTED','INVENTORY_RECONCILED','FULFILLMENT_UPDATED','FULFILLMENT_BACKLOG_DETECTED','DELIVERY_DELAY_REPORTED','FULFILLMENT_ANOMALY_DETECTED','LOW_STOCK_DETECTED','RECOMMENDATION_GENERATED','INTEGRATION_IMPORT_PROCESSED','INTEGRATION_CONNECTOR_UPDATED','INTEGRATION_REPLAY_QUEUED','INTEGRATION_REPLAY_FAILED','INTEGRATION_REPLAY_COMPLETED','SCENARIO_SAVED','SCENARIO_ESCALATION_ADVANCED','SCENARIO_SLA_ESCALATED','SCENARIO_SLA_ACKNOWLEDGED','SCENARIO_APPROVED','SCENARIO_REJECTED','SCENARIO_RESUBMITTED','SCENARIO_ANALYZED','SCENARIO_COMPARED','SCENARIO_EXECUTED')), tenant_code varchar(64), source varchar(80) not null, payload_summary varchar(2048) not null, primary key (id));
create table if not exists customer_orders (total_amount numeric(14,2) not null, blocked_at timestamp(6) with time zone, cancelled_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, delivered_at timestamp(6) with time zone, failed_at timestamp(6) with time zone, fulfilled_at timestamp(6) with time zone, id bigint generated by default as identity, processing_started_at timestamp(6) with time zone, returned_at timestamp(6) with time zone, tenant_id bigint, updated_at timestamp(6) with time zone not null, warehouse_id bigint not null, status varchar(32) not null check (status in ('CREATED','RECEIVED','PROCESSING','PARTIALLY_FULFILLED','FULFILLED','DELIVERED','CANCELLED','RETURNED','FAILED','BLOCKED')), external_order_id varchar(80) not null, status_reason varchar(320), primary key (id), unique (tenant_id, external_order_id));
create table if not exists fulfillment_tasks (exception_count integer not null, fulfilled_units integer not null, total_units integer not null, created_at timestamp(6) with time zone not null, customer_order_id bigint not null unique, delivered_at timestamp(6) with time zone, dispatched_at timestamp(6) with time zone, expected_delivery_at timestamp(6) with time zone, id bigint generated by default as identity, promised_dispatch_at timestamp(6) with time zone, queued_at timestamp(6) with time zone not null, tenant_id bigint, updated_at timestamp(6) with time zone not null, warehouse_id bigint not null, status varchar(32) not null check (status in ('QUEUED','PICKING','PACKED','DISPATCHED','DELAYED','DELIVERED','EXCEPTION')), carrier varchar(80), tracking_reference varchar(120), note varchar(512), primary key (id));
create table if not exists integration_connectors (allow_default_warehouse_fallback boolean not null, enabled boolean not null, mapping_version integer, sync_interval_minutes integer, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, last_pull_attempt_at timestamp(6) with time zone, last_pull_success_at timestamp(6) with time zone, tenant_id bigint, updated_at timestamp(6) with time zone not null, inbound_access_token_hint varchar(24), last_pull_status varchar(32), sync_mode varchar(32) not null check (sync_mode in ('REALTIME_PUSH','BATCH_FILE_DROP','SCHEDULED_PULL')), transformation_policy varchar(32) not null check (transformation_policy in ('NONE','NORMALIZE_CODES')), type varchar(32) not null check (type in ('WEBHOOK_ORDER','CSV_ORDER_IMPORT')), validation_policy varchar(32) not null check (validation_policy in ('STANDARD','STRICT','RELAXED')), default_warehouse_code varchar(40), inbound_access_token_hash varchar(64), source_system varchar(80) not null, support_owner_actor_name varchar(80), display_name varchar(120) not null, notes varchar(240), last_pull_message varchar(512), pull_endpoint_url varchar(512), primary key (id), unique (tenant_id, source_system, type));
create table if not exists integration_import_runs (orders_failed integer not null, orders_imported integer not null, records_received integer not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, status varchar(24) not null check (status in ('SUCCESS','PARTIAL_SUCCESS','FAILURE')), connector_type varchar(32) not null check (connector_type in ('WEBHOOK_ORDER','CSV_ORDER_IMPORT')), tenant_code varchar(64), source_system varchar(80) not null, file_name varchar(160), summary varchar(320) not null, primary key (id));
create table if not exists integration_inbound_records (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, replay_record_id bigint, updated_at timestamp(6) with time zone not null, status varchar(24) not null check (status in ('RECEIVED','ACCEPTED','REJECTED','REPLAY_QUEUED','REPLAYED')), connector_type varchar(32) not null check (connector_type in ('WEBHOOK_ORDER','CSV_ORDER_IMPORT')), warehouse_code varchar(40), failure_code varchar(48) check (failure_code in ('CONNECTOR_NOT_CONFIGURED','MISSING_EXTERNAL_ORDER_ID','MISSING_ITEMS','MISSING_WAREHOUSE_CODE','STRICT_WAREHOUSE_MISMATCH','MISSING_CUSTOMER_REFERENCE','MISSING_OCCURRED_AT','DUPLICATE_PRODUCT_LINES','MISSING_PRODUCT_SKU','INVALID_SOURCE_SYSTEM','INVALID_QUANTITY','INVALID_UNIT_PRICE','MISSING_FILE','EMPTY_CSV','MISSING_CSV_HEADER','MISSING_HEADER_COLUMN','CONNECTOR_SOURCE_MISMATCH','INVALID_CONNECTOR_TOKEN','CONNECTOR_DISABLED','UNSUPPORTED_MAPPING_VERSION','WAREHOUSE_NOT_FOUND','PRODUCT_NOT_FOUND','INVENTORY_NOT_FOUND','INSUFFICIENT_INVENTORY','DUPLICATE_EXTERNAL_ORDER_ID','UNKNOWN')), request_id varchar(64), tenant_code varchar(64), external_order_id varchar(80), replayed_order_external_id varchar(80), source_system varchar(80) not null, ingestion_source varchar(120), file_name varchar(160), failure_message varchar(320), request_payload text not null, primary key (id));
create table if not exists integration_replay_records (replay_attempt_count integer not null, created_at timestamp(6) with time zone not null, dead_lettered_at timestamp(6) with time zone, id bigint generated by default as identity, inbound_record_id bigint, last_attempted_at timestamp(6) with time zone, next_eligible_at timestamp(6) with time zone, resolved_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, status varchar(24) not null check (status in ('PENDING','REPLAY_FAILED','DEAD_LETTERED','REPLAYED')), connector_type varchar(32) not null check (connector_type in ('WEBHOOK_ORDER','CSV_ORDER_IMPORT')), warehouse_code varchar(40) not null, failure_code varchar(48) check (failure_code in ('CONNECTOR_NOT_CONFIGURED','MISSING_EXTERNAL_ORDER_ID','MISSING_ITEMS','MISSING_WAREHOUSE_CODE','STRICT_WAREHOUSE_MISMATCH','MISSING_CUSTOMER_REFERENCE','MISSING_OCCURRED_AT','DUPLICATE_PRODUCT_LINES','MISSING_PRODUCT_SKU','INVALID_SOURCE_SYSTEM','INVALID_QUANTITY','INVALID_UNIT_PRICE','MISSING_FILE','EMPTY_CSV','MISSING_CSV_HEADER','MISSING_HEADER_COLUMN','CONNECTOR_SOURCE_MISMATCH','INVALID_CONNECTOR_TOKEN','CONNECTOR_DISABLED','UNSUPPORTED_MAPPING_VERSION','WAREHOUSE_NOT_FOUND','PRODUCT_NOT_FOUND','INVENTORY_NOT_FOUND','INSUFFICIENT_INVENTORY','DUPLICATE_EXTERNAL_ORDER_ID','UNKNOWN')), tenant_code varchar(64), external_order_id varchar(80) not null, replayed_order_external_id varchar(80), source_system varchar(80) not null, failure_message varchar(320) not null, last_replay_message varchar(320), request_payload text not null, primary key (id));
create table if not exists inventory (id bigint generated by default as identity, last_adjusted_at timestamp(6) with time zone, last_received_at timestamp(6) with time zone, last_reconciled_at timestamp(6) with time zone, product_id bigint not null, quantity_available bigint not null, quantity_inbound bigint, quantity_on_hand bigint, quantity_reserved bigint, reconciliation_variance bigint, reorder_threshold bigint not null, tenant_id bigint, updated_at timestamp(6) with time zone not null, warehouse_id bigint not null, primary key (id), constraint uk_inventory_product_warehouse unique (product_id, warehouse_id));
create table if not exists operational_dispatch_work_items (attempt_count integer not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, occurred_at timestamp(6) with time zone not null, processed_at timestamp(6) with time zone, updated_at timestamp(6) with time zone not null, status varchar(24) not null check (status in ('PENDING','PROCESSING','COMPLETED','FAILED')), update_type varchar(48) not null check (update_type in ('ORDER_FLOW','FULFILLMENT_UPDATE','INVENTORY_UPDATE','INTEGRATION_STATE','SYSTEM_RESEEDED')), request_id varchar(80) not null, tenant_code varchar(80) not null, source varchar(120) not null, last_error varchar(320), primary key (id));
create table if not exists order_items (cancelled_quantity integer not null, fulfilled_quantity integer not null, quantity integer not null, reserved_quantity integer not null, returned_quantity integer not null, unit_price numeric(14,2) not null, customer_order_id bigint not null, id bigint generated by default as identity, product_id bigint not null, tenant_id bigint, primary key (id));
create table if not exists products (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint, updated_at timestamp(6) with time zone not null, catalog_sku varchar(64), category varchar(120) not null, name varchar(120) not null, sku varchar(128) not null unique, primary key (id));
create table if not exists recommendations (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint, priority varchar(32) not null check (priority in ('MEDIUM','HIGH','CRITICAL')), type varchar(32) not null check (type in ('REORDER_STOCK','REORDER_URGENTLY','TRANSFER_STOCK','PRIORITIZE_FULFILLMENT','ESCALATE_LOGISTICS','INVESTIGATE_LOGISTICS_ANOMALY')), title varchar(180) not null, description varchar(1024) not null, policy_explanation varchar(1024), primary key (id));
create table if not exists scenario_runs (revision_number integer, risk_score integer, approval_due_at timestamp(6) with time zone, approved_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, rejected_at timestamp(6) with time zone, review_approved_at timestamp(6) with time zone, revision_of_scenario_run_id bigint, sla_acknowledged_at timestamp(6) with time zone, sla_escalated_at timestamp(6) with time zone, tenant_id bigint, approval_policy varchar(24) not null check (approval_policy in ('STANDARD','ESCALATED')), review_priority varchar(24) check (review_priority in ('MEDIUM','HIGH','CRITICAL')), approval_stage varchar(32) not null check (approval_stage in ('NOT_REQUIRED','PENDING_REVIEW','PENDING_FINAL_APPROVAL','APPROVED','REJECTED')), approval_status varchar(32) not null check (approval_status in ('NOT_REQUIRED','PENDING_APPROVAL','APPROVED','REJECTED')), type varchar(32) not null check (type in ('SAVED_PLAN','PREVIEW','COMPARISON','EXECUTION')), warehouse_code varchar(40), approved_by varchar(80), final_approval_owner varchar(80), recommended_option varchar(80), rejected_by varchar(80), requested_by varchar(80), review_approved_by varchar(80), review_owner varchar(80), sla_acknowledged_by varchar(80), sla_escalated_to varchar(80), title varchar(120) not null, approval_note varchar(240), rejection_reason varchar(240), review_approval_note varchar(240), sla_acknowledgement_note varchar(240), summary varchar(2048) not null, request_payload varchar(4096), primary key (id));
create table if not exists tenant_operational_policies (backlog_clear_hours_threshold float(53) not null, backlog_critical_count integer not null, backlog_risk_count integer not null, critical_risk_score_threshold integer not null, delayed_shipment_count_threshold integer not null, delivery_delay_tolerance_hours float(53) not null, depletion_risk_hours_threshold float(53) not null, final_approval_hours_critical integer not null, final_approval_hours_high integer not null, final_approval_hours_medium integer not null, high_risk_score_threshold integer not null, low_stock_critical_ratio float(53) not null, overdue_dispatch_count_threshold integer not null, rapid_consumption_threshold_ratio float(53) not null, rapid_consumption_units_minimum integer not null, review_hours_critical integer not null, review_hours_high integer not null, review_hours_medium integer not null, urgent_depletion_risk_hours_threshold float(53) not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint not null, updated_at timestamp(6) with time zone not null, backlog_critical_severity varchar(32) check (backlog_critical_severity in ('MEDIUM','HIGH','CRITICAL')), backlog_recommendation_priority varchar(32) check (backlog_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), backlog_risk_severity varchar(32) check (backlog_risk_severity in ('MEDIUM','HIGH','CRITICAL')), critical_low_stock_recommendation_priority varchar(32) check (critical_low_stock_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), delivery_delay_recommendation_priority varchar(32) check (delivery_delay_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), delivery_delay_severity varchar(32) check (delivery_delay_severity in ('MEDIUM','HIGH','CRITICAL')), depletion_risk_recommendation_priority varchar(32) check (depletion_risk_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), depletion_risk_severity varchar(32) check (depletion_risk_severity in ('MEDIUM','HIGH','CRITICAL')), escalated_approval_minimum_priority varchar(32) check (escalated_approval_minimum_priority in ('MEDIUM','HIGH','CRITICAL')), escalation_owner_role varchar(32) not null check (escalation_owner_role in ('TENANT_ADMIN','REVIEW_OWNER','FINAL_APPROVER','ESCALATION_OWNER','INTEGRATION_ADMIN','INTEGRATION_OPERATOR')), final_approver_role varchar(32) not null check (final_approver_role in ('TENANT_ADMIN','REVIEW_OWNER','FINAL_APPROVER','ESCALATION_OWNER','INTEGRATION_ADMIN','INTEGRATION_OPERATOR')), fulfillment_anomaly_recommendation_priority varchar(32) check (fulfillment_anomaly_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), fulfillment_anomaly_severity varchar(32) check (fulfillment_anomaly_severity in ('MEDIUM','HIGH','CRITICAL')), low_stock_critical_severity varchar(32) check (low_stock_critical_severity in ('MEDIUM','HIGH','CRITICAL')), low_stock_recommendation_priority varchar(32) check (low_stock_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), low_stock_severity varchar(32) check (low_stock_severity in ('MEDIUM','HIGH','CRITICAL')), review_owner_role varchar(32) not null check (review_owner_role in ('TENANT_ADMIN','REVIEW_OWNER','FINAL_APPROVER','ESCALATION_OWNER','INTEGRATION_ADMIN','INTEGRATION_OPERATOR')), urgent_depletion_risk_recommendation_priority varchar(32) check (urgent_depletion_risk_recommendation_priority in ('MEDIUM','HIGH','CRITICAL')), urgent_depletion_risk_severity varchar(32) check (urgent_depletion_risk_severity in ('MEDIUM','HIGH','CRITICAL')), primary key (id), constraint uk_tenant_operational_policy_tenant unique (tenant_id));
create table if not exists tenants (active boolean not null, password_rotation_days integer not null, session_timeout_minutes integer not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, security_policy_version bigint not null, updated_at timestamp(6) with time zone not null, code varchar(64) not null unique, name varchar(120) not null, description varchar(240), primary key (id));
create table if not exists warehouses (created_at timestamp(6) with time zone not null, id bigint generated by default as identity, tenant_id bigint, updated_at timestamp(6) with time zone not null, code varchar(40) not null, location varchar(120) not null, name varchar(120) not null, primary key (id), unique (tenant_id, code));
